import React, { useMemo, useState } from "react";

const API_URL = process.env.REACT_APP_API_URL || "";
const API_BASE = API_URL.replace(/\/api\/?$/, "");

const getInitials = (text = "") => text.trim().slice(0, 2).toUpperCase() || "??";
const toAttachmentUrl = (url) => {
  if (!url) return "";
  if (url.startsWith("http://") || url.startsWith("https://")) return url;
  return `${API_BASE}${url}`;
};

export default function DiscoverPanel({ user, rooms, onSelectRoom, onJoinRoom }) {
  const [query, setQuery] = useState("");

  const { roomResults, peopleResults } = useMemo(() => {
    const term = query.trim().toLowerCase();
    const match = (value) => !term || value.toLowerCase().includes(term);

    const roomResults = rooms.filter(
      (room) => match(room.name || "") || match(room.description || "")
    );

    const peopleMap = new Map();
    rooms.forEach((room) => {
      (room.members || []).forEach((member) => {
        if (!member || member._id === user?.id) return;
        const existing = peopleMap.get(member._id) || { ...member, rooms: [] };
        existing.rooms.push(room);
        peopleMap.set(member._id, existing);
      });
    });

    const peopleResults = Array.from(peopleMap.values()).filter((person) =>
      match(person.username || "")
    );

    return { roomResults, peopleResults };
  }, [rooms, query, user]);

  const handleOpenPerson = (person) => {
    const primaryRoom = person.rooms?.[0];
    if (!primaryRoom) return;
    const isMember = primaryRoom.members?.some((member) => (member._id || member.id) === user?.id);
    if (isMember) {
      onSelectRoom(primaryRoom);
    } else {
      onJoinRoom(primaryRoom._id);
    }
  };

  return (
    <section className="discover-panel glass">
      <header className="discover-head">
        <div>
          <p className="eyebrow">Discover</p>
          <h2>Find rooms & people</h2>
        </div>
        <div className="discover-search">
          <input
            type="text"
            value={query}
            onChange={(event) => setQuery(event.target.value)}
            placeholder="Search rooms or people"
            aria-label="Search rooms or people"
          />
          <span className="kbd">/</span>
        </div>
      </header>

      <div className="discover-grid">
        <div className="discover-card">
          <div className="discover-card-head">
            <h3>Rooms</h3>
            <small>{roomResults.length}</small>
          </div>
          <div className="discover-list">
            {roomResults.length === 0 ? (
              <p className="muted">No rooms match that search.</p>
            ) : (
              roomResults.map((room) => {
                const isMember = room.members?.some((member) => (member._id || member.id) === user?.id);
                const initials = getInitials(room.name);
                const avatarUrl = toAttachmentUrl(room.avatarUrl);
                return (
                  <article key={room._id} className="discover-item">
                    {avatarUrl ? (
                      <img src={avatarUrl} alt={room.name} className="discover-avatar" />
                    ) : (
                      <span className="discover-avatar fallback">{initials}</span>
                    )}
                    <div className="discover-copy">
                      <strong>{room.name}</strong>
                      <span className="muted">{room.description || "Open chat room"}</span>
                      <small className="muted">{room.members?.length || 0} members</small>
                    </div>
                    <button
                      type="button"
                      className="ghost-btn"
                      onClick={() => (isMember ? onSelectRoom(room) : onJoinRoom(room._id))}
                    >
                      {isMember ? "Open" : "Join"}
                    </button>
                  </article>
                );
              })
            )}
          </div>
        </div>

        <div className="discover-card">
          <div className="discover-card-head">
            <h3>People</h3>
            <small>{peopleResults.length}</small>
          </div>
          <div className="discover-list">
            {peopleResults.length === 0 ? (
              <p className="muted">No people match that search.</p>
            ) : (
              peopleResults.map((person) => {
                const initials = getInitials(person.username);
                const sharedRoom = person.rooms?.[0];
                return (
                  <article key={person._id} className="discover-item">
                    <span className="discover-avatar fallback">{initials}</span>
                    <div className="discover-copy">
                      <strong>{person.username}</strong>
                      <span className="muted">
                        {sharedRoom ? `Seen in ${sharedRoom.name}` : "No shared rooms yet"}
                      </span>
                      <small className="muted">{person.rooms?.length || 0} rooms</small>
                    </div>
                    {sharedRoom ? (
                      <button type="button" className="ghost-btn" onClick={() => handleOpenPerson(person)}>
                        Chat
                      </button>
                    ) : null}
                  </article>
                );
              })
            )}
          </div>
        </div>
      </div>
    </section>
  );
}
